"""
This module contains classes for representing and manipulating the checkers board.
"""

class Piece:
    RED = 'R'
    BLACK = 'B'

    def __init__(self, color):
        self.color = color

    def __str__(self):
        return f"{self.color}"


class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        for i in range(3):
            for j in (0, 2, 4, 6):
                self.board[i][j] = Piece(BLACK)
        for i in range(5, 8):
            for j in (1, 3, 5, 7):
                self.board[i][j] = Piece(RED)

    def get_piece(self, row, col):
        return self.board[row][col]

    def move_piece(self, start_row, start_col, end_row, end_col):
        piece = self.get_piece(start_row, start_col)
        if piece:
            self.board[end_row][end_col] = piece
            self.board[start_row][start_col] = None

    def __str__(self):
        board_str = ""
        for row in self.board:
            board_str += " ".join(str(piece) if piece else "." for piece in row)
            board_str += "\n"
        return board_str
```

#### `game.py`

```python
"""
This module contains classes for managing the game state and player interactions.
"""

class Player:
    def __init__(self, color):
        self.color = color


class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = Player(Piece.RED)

    def switch_turn(self):
        if self.current_player.color == Piece.RED:
            self.current_player.color = Piece.BLACK
        else:
            self.current_player.color = Piece.RED

    def make_move(self, start_row, start_col, end_row, end_col):
        # Implement move validation and execution
        piece = self.board.get_piece(start_row, start_col)
        if piece and piece.color == self.current_player.color:
            self.board.move_piece(start_row, start_col, end_row, end_col)
            self.switch_turn()


if __name__ == "__main__":
    game = Game()
    print(game.board)
```

